<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover">
<title>Yoru Shield VPN</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&family=Source+Code+Pro:wght@400;700&display=swap');

:root {
  --bg-main: #0a0e17;
  --bg-card: rgba(20, 25, 38, 0.6);
  --bg-card-solid: #131824;
  --border: rgba(255, 255, 255, 0.08);
  --text-main: #f8fafc;
  --text-muted: #94a3b8;
  --accent-indigo: #6366f1;
  --accent-cyan: #06b6d4;
  --accent-a: #6366f1;
  --accent-b: #06b6d4;
  --success: #10b981;
  --warning: #f59e0b;
  --danger: #ef4444;
  --nav-h: 75px;
  --glass-blur: blur(12px);
  --orb-glow: rgba(99,102,241,0.25);
  --bg-glow1: rgba(99, 102, 241, 0.08);
  --bg-glow2: rgba(6, 182, 212, 0.08);
  --safe-top: env(safe-area-inset-top, 0px);
}

[data-theme="light"] {
  --bg-main: #f0f4ff;
  --bg-card: rgba(255,255,255,0.75);
  --bg-card-solid: #ffffff;
  --border: rgba(0,0,0,0.08);
  --text-main: #0f172a;
  --text-muted: #64748b;
  --accent-indigo: #4f46e5;
  --accent-cyan: #0891b2;
  --accent-a: #4f46e5;
  --accent-b: #0891b2;
  --orb-glow: rgba(79,70,229,0.2);
  --bg-glow1: rgba(99,102,241,0.1);
  --bg-glow2: rgba(6,182,212,0.1);
}
[data-theme="light"] .bottom-nav { background: rgba(255,255,255,0.85); }
[data-theme="light"] .nav-btn { color: #94a3b8; }
[data-theme="light"] .nav-btn.active { color: var(--accent-indigo); background: rgba(79,70,229,0.07); }
[data-theme="light"] .modal-box { background: #f8faff; }
[data-theme="light"] .input-field input { color: #0f172a; }
[data-theme="light"] #log-container { background: rgba(0,0,0,0.04); }
[data-theme="light"] .log-entry.INFO { color: #0f172a; }
[data-theme="light"] .toast { background: rgba(255,255,255,0.97); color: #0f172a; }
[data-theme="light"] .wallpaper-overlay { opacity: 0.15; }

[data-theme="red"] { --bg-main:#100808;--bg-card:rgba(40,12,12,0.65);--bg-card-solid:#1a0909;--border:rgba(255,80,80,0.12);--text-main:#fff5f5;--text-muted:#f87171;--accent-indigo:#ef4444;--accent-cyan:#fb923c;--accent-a:#ef4444;--accent-b:#fb923c;--orb-glow:rgba(239,68,68,0.3);--bg-glow1:rgba(239,68,68,0.1);--bg-glow2:rgba(251,146,60,0.08); }
[data-theme="blue"] { --bg-main:#050d1a;--bg-card:rgba(8,20,50,0.65);--bg-card-solid:#08132e;--border:rgba(59,130,246,0.15);--text-main:#eff6ff;--text-muted:#93c5fd;--accent-indigo:#3b82f6;--accent-cyan:#22d3ee;--accent-a:#3b82f6;--accent-b:#22d3ee;--orb-glow:rgba(59,130,246,0.3);--bg-glow1:rgba(59,130,246,0.1);--bg-glow2:rgba(34,211,238,0.08); }
[data-theme="gold"] { --bg-main:#0d0a00;--bg-card:rgba(35,28,0,0.65);--bg-card-solid:#1a1500;--border:rgba(234,179,8,0.15);--text-main:#fefce8;--text-muted:#fde047;--accent-indigo:#eab308;--accent-cyan:#f97316;--accent-a:#eab308;--accent-b:#f97316;--orb-glow:rgba(234,179,8,0.3);--bg-glow1:rgba(234,179,8,0.1);--bg-glow2:rgba(249,115,22,0.08); }
[data-theme="neon"] { --bg-main:#020d06;--bg-card:rgba(4,28,12,0.65);--bg-card-solid:#041a0a;--border:rgba(16,185,129,0.15);--text-main:#f0fdf4;--text-muted:#6ee7b7;--accent-indigo:#10b981;--accent-cyan:#34d399;--accent-a:#10b981;--accent-b:#34d399;--orb-glow:rgba(16,185,129,0.3);--bg-glow1:rgba(16,185,129,0.1);--bg-glow2:rgba(52,211,153,0.08); }
[data-theme="rose"] { --bg-main:#0f0510;--bg-card:rgba(35,8,38,0.65);--bg-card-solid:#1a0520;--border:rgba(244,114,182,0.15);--text-main:#fdf4ff;--text-muted:#f0abfc;--accent-indigo:#ec4899;--accent-cyan:#a855f7;--accent-a:#ec4899;--accent-b:#a855f7;--orb-glow:rgba(236,72,153,0.3);--bg-glow1:rgba(236,72,153,0.1);--bg-glow2:rgba(168,85,247,0.08); }
[data-theme="pulse"] {
  --bg-main:#07050f;--bg-card:rgba(20,12,40,0.65);--bg-card-solid:#10082a;--border:rgba(139,92,246,0.15);--text-main:#f5f3ff;--text-muted:#c4b5fd;--accent-indigo:#8b5cf6;--accent-cyan:#06b6d4;--accent-a:#8b5cf6;--accent-b:#06b6d4;--orb-glow:rgba(139,92,246,0.35);--bg-glow1:rgba(139,92,246,0.12);--bg-glow2:rgba(6,182,212,0.08);
}
[data-theme="pulse"] .app-logo { background: linear-gradient(135deg, #8b5cf6, #ec4899, #06b6d4); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-size: 200%; animation: gradShift 3s ease infinite; }
[data-theme="pulse"] .app-logo-icon { background: linear-gradient(135deg, #8b5cf6, #ec4899); animation: gradShift 3s ease infinite; }
@keyframes gradShift { 0%,100%{background-position:0% 50%} 50%{background-position:100% 50%} }
[data-theme="pulse"] .bottom-nav { border-color: rgba(139,92,246,0.2); box-shadow: 0 10px 40px rgba(139,92,246,0.2); }
[data-theme="pulse"] .nav-btn.active svg { animation: colorCycle 4s linear infinite; }
@keyframes colorCycle { 0%{color:#8b5cf6} 33%{color:#ec4899} 66%{color:#06b6d4} 100%{color:#8b5cf6} }

[data-layout="compact"] .yoru-card { padding: 10px; border-radius: 14px; }
[data-layout="compact"] .status-title { font-size: 20px; }
[data-layout="compact"] .bottom-nav { height: 64px; border-radius: 18px; }

[data-layout="extreme-glass"] .yoru-card { backdrop-filter: blur(24px); -webkit-backdrop-filter: blur(24px); background: rgba(20, 25, 38, 0.3); border: 1px solid rgba(255,255,255,0.15); }
[data-layout="extreme-glass"] .bottom-nav { background: rgba(15,20,30,0.6); backdrop-filter: blur(24px); }

[data-layout="neumorphic"] .yoru-card {
  background: #e0e5ec; border: none;
  box-shadow: 8px 8px 16px rgba(163, 177, 198, 0.6), -8px -8px 16px rgba(255, 255, 255, 0.8); border-radius: 24px;
}
[data-layout="neumorphic"] .bottom-nav { background: #e0e5ec; box-shadow: 8px 8px 16px rgba(163, 177, 198, 0.6), -8px -8px 16px rgba(255, 255, 255, 0.8); border: none; }
[data-layout="neumorphic"] .app-shell { background: #e0e5ec; }
[data-layout="neumorphic"] .toast { background: #e0e5ec; color: #1e293b; }
[data-layout="neumorphic"] .modal-box { background: #e0e5ec; }

[data-layout="minimal"] .yoru-card { border-radius: 8px; backdrop-filter: none; -webkit-backdrop-filter: none; }
[data-layout="minimal"] .bottom-nav { border-radius: 8px; backdrop-filter: none; background: rgba(15,20,30,0.95); }

[data-layout="futuristic"] .yoru-card {
  border-radius: 4px; border-width: 1.5px; border-style: solid; border-color: rgba(6, 182, 212, 0.4); box-shadow: 0 0 10px rgba(0,229,255,0.2);
}
[data-layout="futuristic"] .bottom-nav { border-radius: 4px; border: 1.5px solid rgba(6, 182, 212, 0.4); box-shadow: 0 0 15px rgba(0,229,255,0.3); background: rgba(0,20,30,0.8); }
[data-layout="futuristic"] .app-logo { font-family: 'Courier New', monospace; }

* { box-sizing: border-box; -webkit-tap-highlight-color: transparent; margin: 0; padding: 0; }
html, body { min-height: 100%; background: var(--bg-main); overflow-x: hidden; }

body {
  font-family: 'Outfit', system-ui, sans-serif;
  color: var(--text-main);
  transition: background-color 0.4s ease, color 0.4s ease;
  background-image:
    radial-gradient(circle at 15% 50%, var(--bg-glow1), transparent 25%),
    radial-gradient(circle at 85% 30%, var(--bg-glow2), transparent 25%);
}

button { cursor: pointer; touch-action: manipulation; user-select: none; border: none; background: none; font-family: inherit; }

.wallpaper-overlay {
  position: fixed; inset: 0; z-index: -2; pointer-events: none;
  background-image: url('https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&w=1000&q=80');
  background-size: cover; background-position: center; background-repeat: no-repeat;
  opacity: 0.06; mix-blend-mode: screen; transition: opacity 0.4s;
}

.celestial-body {
  position: fixed; top: calc(25px + var(--safe-top)); right: 25px; font-size: 48px; z-index: 1; pointer-events: none;
  animation: floatCelestial 6s ease-in-out infinite alternate; transition: opacity 0.4s, filter 0.4s;
}
.celestial-sun { opacity: 0.35; filter: drop-shadow(0 0 12px rgba(255,200,0,0.25)); }
[data-theme="light"] .celestial-sun { opacity: 1; filter: drop-shadow(0 0 24px rgba(255,200,0,0.9)); }
.celestial-moon { filter: drop-shadow(0 0 18px rgba(255,255,255,0.6)); }
@keyframes floatCelestial { 0%{transform:translateY(0px) rotate(-5deg)} 100%{transform:translateY(15px) rotate(5deg)} }

.fx-star {
  position: fixed; background-color: #fff; border-radius: 50%; pointer-events: none; z-index: 0;
  opacity: 0; animation: twinkleStar linear infinite;
}
[data-theme="light"] .fx-star { background-color: #0f172a; }
@keyframes twinkleStar { 0%{opacity:0;transform:scale(0.5)} 50%{opacity:0.6;transform:scale(1)} 100%{opacity:0;transform:scale(0.5)} }

.floating-bubble {
  position: fixed; border-radius: 50%; pointer-events: none; z-index: 0;
  background: radial-gradient(circle at 30% 30%, rgba(255,255,255,0.15), rgba(99,102,241,0.1));
  animation: floatBubble ease-in-out infinite;
}
@keyframes floatBubble {
  0%{transform:translateY(0px) translateX(0px) scale(1)}
  25%{transform:translateY(-30px) translateX(15px) scale(1.1)}
  50%{transform:translateY(-15px) translateX(-10px) scale(0.95)}
  75%{transform:translateY(-40px) translateX(-20px) scale(1.05)}
  100%{transform:translateY(0px) translateX(0px) scale(1)}
}

.app-shell {
  width: min(100%, 480px); margin: 0 auto;
  min-height: 100vh; display: flex; flex-direction: column;
  padding-bottom: calc(var(--nav-h) + env(safe-area-inset-bottom) + 20px);
  padding-top: var(--safe-top);
  transition: margin-left 0.4s cubic-bezier(0.4,0,0.2,1), filter 0.3s; position: relative; z-index: 2;
}

.app-header { display: flex; justify-content: space-between; align-items: center; padding: 20px 24px; }
.app-logo {
  font-size: 24px; font-weight: 900; letter-spacing: -0.5px;
  background: linear-gradient(135deg, #fff, #a5b4fc);
  -webkit-background-clip: text; -webkit-text-fill-color: transparent;
  display: flex; align-items: center; gap: 8px;
}
.app-logo-icon {
  width: 28px; height: 28px; border-radius: 8px;
  background: linear-gradient(135deg, var(--accent-a), var(--accent-b));
  display: grid; place-items: center; color: #fff; font-size: 14px;
  box-shadow: 0 4px 12px var(--orb-glow);
  -webkit-text-fill-color: #fff;
}
.app-version {
  font-size: 11px; font-weight: 700; color: var(--text-muted);
  background: rgba(255,255,255,0.05); padding: 4px 10px; border-radius: 20px;
  border: 1px solid var(--border);
}

.page { display: none; flex-direction: column; flex: 1; padding: 0 20px; animation: fadeIn 0.3s ease; }
.page.active { display: flex; }
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }

.page-title-box { margin-bottom: 20px; }
.page-title { font-size: 28px; font-weight: 800; color: var(--text-main); }
.page-subtitle { font-size: 14px; color: var(--text-muted); font-weight: 400; margin-top: 4px; }

.hero-area { display: flex; flex-direction: column; align-items: center; margin-top: 20px; margin-bottom: 28px; }

.status-title { font-size: 24px; font-weight: 800; text-align: center; color: var(--text-main); transition: color 0.3s; margin-bottom: 4px; }
body.st-conectado .status-title { color: var(--success); }
body.st-conectando .status-title { color: var(--warning); }
body.st-erro .status-title { color: var(--danger); }
.status-sub { font-size: 14px; color: var(--text-muted); text-align: center; font-weight: 400; max-width: 85%; margin-bottom: 20px; }

.connect-actions { display: flex; gap: 12px; width: 100%; position: relative; z-index: 15; }
.btn-connect-main {
  flex: 1; padding: 16px; border-radius: 16px;
  background: linear-gradient(135deg, var(--accent-a), var(--accent-b));
  color: #fff; font-size: 15px; font-weight: 700;
  cursor: pointer; transition: all 0.3s cubic-bezier(0.4,0,0.2,1);
  box-shadow: 0 8px 24px rgba(0,0,0,0.3); position: relative; overflow: hidden;
  display: flex; align-items: center; justify-content: center; gap: 8px;
}
.btn-connect-main:active { transform: scale(0.97); opacity: 0.9; }
.btn-connect-main:active::before {
  content: ''; position: absolute; inset: -20px; border-radius: 50%;
  background: radial-gradient(circle, rgba(255,255,255,0.3) 0%, transparent 60%);
  animation: ripple 0.6s ease-out;
}
@keyframes ripple { 0%{transform:scale(0);opacity:1} 100%{transform:scale(1);opacity:0} }

.btn-connect-main svg { width: 20px; height: 20px; }

body.st-conectado .btn-connect-main { background: linear-gradient(135deg,#10b981,#059669); box-shadow: 0 8px 24px rgba(16,185,129,0.3); }
body.st-conectando .btn-connect-main { background: linear-gradient(135deg,#f59e0b,#d97706); box-shadow: 0 8px 24px rgba(245,158,11,0.3); }
body.st-erro .btn-connect-main { background: linear-gradient(135deg,#ef4444,#dc2626); box-shadow: 0 8px 24px rgba(239,68,68,0.3); }

.btn-logs-quick {
  width: 56px; border-radius: 16px;
  background: rgba(255,255,255,0.08); border: 1px solid var(--border);
  color: var(--text-muted); font-size: 22px;
  display: grid; place-items: center; cursor: pointer;
  transition: all 0.2s; backdrop-filter: blur(8px);
}
.btn-logs-quick:active { background: rgba(255,255,255,0.15); transform: scale(0.95); }

.timer-bar { display: none; align-items: center; justify-content: center; gap: 8px; margin-top: 16px; padding: 8px 20px; border-radius: 100px; background: rgba(16,185,129,0.1); border: 1px solid rgba(16,185,129,0.2); }
.timer-bar.show { display: flex; }
.timer-label { color: var(--success); font-weight: 700; font-size: 11px; letter-spacing: 1px; text-transform: uppercase; }
.timer-val { color: var(--success); font-weight: 800; font-size: 16px; font-variant-numeric: tabular-nums; }

.yoru-card { background: var(--bg-card); border-radius: 20px; padding: 16px; border: 1px solid var(--border); backdrop-filter: var(--glass-blur); margin-bottom: 12px; transition: background 0.4s, border-color 0.4s, transform 0.2s, box-shadow 0.2s; }
.yoru-card:active { transform: scale(0.98); }

.creds-card { margin-bottom: 12px; position: relative; overflow: hidden; }
.server-card, #settings-card { position: relative; overflow: hidden; }
.blocked-overlay {
  display: none;
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0.5);
  backdrop-filter: blur(3px);
  -webkit-backdrop-filter: blur(3px);
  border-radius: inherit;
  z-index: 5;
  justify-content: center;
  align-items: center;
  color: #fff;
  font-weight: 700;
  font-size: 14px;
  gap: 8px;
  pointer-events: auto;
  flex-direction: row;
}
.blocked .blocked-overlay { display: flex; }
.blocked input, .blocked select, .blocked button:not(.btn-connect-main):not(.btn-logs-quick) {
  pointer-events: none !important;
  opacity: 0.5 !important;
}
.blocked .creds-toggle { pointer-events: none; opacity: 0.5; }

.creds-card-header { display: flex; align-items: center; justify-content: space-between; margin-bottom: 14px; }
.creds-card-title { font-size: 12px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: var(--text-muted); display: flex; align-items: center; gap: 8px; }
.creds-toggle { font-size: 11px; font-weight: 700; padding: 6px 14px; border-radius: 20px; background: rgba(99,102,241,0.1); color: var(--accent-a); transition: all 0.2s; }
.creds-toggle:active { background: rgba(99,102,241,0.2); }
.input-group { margin-bottom: 10px; }
.input-label { font-size: 11px; font-weight: 600; color: var(--text-muted); margin-bottom: 6px; display: flex; align-items: center; gap: 6px; }
.input-field { position: relative; }
.input-field input {
  width: 100%; padding: 12px 16px; border-radius: 12px; border: 1px solid var(--border);
  background: rgba(0,0,0,0.2); color: var(--text-main); font-size: 14px; font-family: inherit;
  outline: none; transition: border 0.2s, box-shadow 0.2s;
}
.input-field input:focus { border-color: var(--accent-a); box-shadow: 0 0 0 3px rgba(99,102,241,0.15); }
.input-eye { position: absolute; right: 12px; top: 50%; transform: translateY(-50%); color: var(--text-muted); font-size: 16px; cursor: pointer; background: none; border: none; padding: 4px; }

.server-card { display: flex; align-items: center; gap: 16px; cursor: pointer; transition: transform 0.2s; }
.server-card:active { transform: scale(0.98); }
.sc-icon { width: 48px; height: 48px; border-radius: 14px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.05); display: grid; place-items: center; font-size: 20px; overflow: hidden; flex-shrink: 0; }
.sc-icon img { width: 100%; height: 100%; object-fit: cover; }
.sc-meta { flex: 1; min-width: 0; }
.sc-label { font-size: 10px; font-weight: 700; color: var(--accent-b); letter-spacing: 1px; text-transform: uppercase; margin-bottom: 2px; }
.sc-title { font-size: 16px; font-weight: 700; color: var(--text-main); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.sc-sub { font-size: 12px; color: var(--text-muted); margin-top: 2px; font-weight: 500; }
.sc-chev { color: var(--text-muted); font-size: 20px; }

.message-card { display: none; align-items: center; gap: 14px; background: rgba(245,158,11,0.05); border-color: rgba(245,158,11,0.2); margin-bottom: 12px; }
.message-card.show { display: flex; }
.msg-icon { font-size: 22px; flex-shrink: 0; }
.msg-title { font-size: 11px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: var(--warning); }
.msg-text { font-size: 13px; color: rgba(255,255,255,0.9); margin-top: 2px; line-height: 1.4; }

.list-item { display: flex; align-items: center; gap: 14px; padding: 16px; border-radius: 18px; margin-bottom: 10px; background: var(--bg-card); border: 1px solid var(--border); cursor: pointer; transition: all 0.2s; }
.list-item:active { transform: scale(0.98); }
.list-item.selected { border-color: var(--accent-a); background: rgba(99,102,241,0.08); }
.li-icon { width: 44px; height: 44px; border-radius: 12px; display: grid; place-items: center; background: rgba(255,255,255,0.05); overflow: hidden; font-size: 20px; flex-shrink: 0; }
.li-icon img { width: 100%; height: 100%; object-fit: cover; }
.li-main { flex: 1; min-width: 0; }
.li-title { font-weight: 700; font-size: 15px; color: var(--text-main); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.li-sub { color: var(--text-muted); font-size: 12px; margin-top: 2px; font-weight: 500; }
.li-check { color: var(--accent-a); display: none; font-size: 20px; font-weight: 900; }
.list-item.selected .li-check { display: block; }

.dashboard-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.speed-card { background: var(--bg-card); border-radius: 20px; padding: 16px; border: 1px solid var(--border); transition: background 0.4s, border-color 0.4s; }
.speed-label { font-size: 11px; font-weight: 700; color: var(--text-muted); text-transform: uppercase; letter-spacing: 1px; display: flex; align-items: center; gap: 6px; }
.speed-val { font-size: 22px; font-weight: 800; margin-top: 8px; color: var(--text-main); font-variant-numeric: tabular-nums; }
.c-dl { color: var(--accent-b); } .c-ul { color: var(--success); }

.checkuser-card { display: none; }
.checkuser-card.show { display: block; }
.cu-title { font-size: 12px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: var(--text-main); margin-bottom: 14px; display: flex; align-items: center; gap: 8px; }
.cu-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.cu-item { background: rgba(255,255,255,0.02); padding: 10px; border-radius: 12px; }
.cu-item-label { font-size: 11px; color: var(--text-muted); font-weight: 600; text-transform: uppercase; }
.cu-item-value { font-size: 14px; font-weight: 700; color: var(--text-main); margin-top: 4px; }
.cu-item-value.green { color: var(--success); }

.time-card { display: none; border-color: rgba(245,158,11,0.2); }
.time-card.show { display: block; }
.time-card-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 12px; }
.time-card-title { font-size: 11px; font-weight: 800; letter-spacing: 1px; text-transform: uppercase; color: var(--warning); }
