<script>
(function () {
'use strict';

var THEME_KEY = 'yoru_theme', LAYOUT_KEY = 'yoru_layout', RADICAL_KEY = 'yoru_radical';
var isXrayMode = false;

window.setTheme = function (id) {
  document.documentElement.setAttribute('data-theme', id === 'dark' ? '' : id);
  document.querySelectorAll('.theme-chip').forEach(function (c) { c.classList.toggle('active', c.getAttribute('data-theme-id') === id); });
  try { localStorage.setItem(THEME_KEY, id); } catch(e) {}
  try { if (window.Android && typeof Android.saveTheme === 'function') Android.saveTheme(id); } catch(e) {}
};
function loadTheme() {
  var saved = null;
  try { if (window.Android && typeof Android.getSavedTheme === 'function') saved = Android.getSavedTheme(); } catch(e) {}
  if (!saved) { try { saved = localStorage.getItem(THEME_KEY); } catch(e) {} }
  if (saved && saved !== 'dark') setTheme(saved);
}

window.setLayout = function (id) {
  document.documentElement.setAttribute('data-layout', id === 'default' ? '' : id);
  document.querySelectorAll('#layout-grid .layout-chip').forEach(function (c) { c.classList.toggle('active', c.getAttribute('data-layout-id') === id); });
  try { localStorage.setItem(LAYOUT_KEY, id); } catch(e) {}
  try { if (window.Android && typeof Android.saveLayout === 'function') Android.saveLayout(id); } catch(e) {}
  toast('Estilo visual aplicado!', 'ok');
};
function loadLayout() {
  var saved = null;
  try { if (window.Android && typeof Android.getSavedLayout === 'function') saved = Android.getSavedLayout(); } catch(e) {}
  if (!saved) { try { saved = localStorage.getItem(LAYOUT_KEY); } catch(e) {} }
  if (saved && saved !== 'default') setLayout(saved);
}

var currentRadical = 'none';

function removeRadial() { var menu = document.getElementById('radial-menu'); if (menu) menu.innerHTML = ''; document.removeEventListener('scroll', updateRadialPos); window.removeEventListener('resize', updateRadialPos); }
function applyRadial() {
  removeRadial();
  var menu = document.getElementById('radial-menu');
  var target = document.querySelector('.btn-connect-main');
  if (!target || !menu) return;
  var rect = target.getBoundingClientRect();
  var cx = rect.left + rect.width/2, cy = rect.top + rect.height/2, r = 130;
  var items = [
    { label: 'Home', icon: '🏠', page: 'home' },
    { label: 'Redes', icon: '🌐', page: 'servers' },
    { label: 'Painel', icon: '📊', page: 'speed' },
    { label: 'Grupo', icon: '💬', action: function(){ if(window.Android)Android.openChat(); } }
  ];
  items.forEach(function(item, i) {
    var angle = (i / items.length) * Math.PI * 2 - Math.PI/2;
    var btn = document.createElement('button');
    btn.className = 'radial-btn';
    btn.innerHTML = item.icon;
    btn.title = item.label;
    btn.style.left = (cx + Math.cos(angle) * r - 28) + 'px';
    btn.style.top = (cy + Math.sin(angle) * r - 28) + 'px';
    btn.onclick = function() { if (item.page) showPage(item.page); if (item.action) item.action(); };
    menu.appendChild(btn);
  });
  updateRadialPos = function() {
    var rect2 = target.getBoundingClientRect();
    var cx2 = rect2.left + rect2.width/2, cy2 = rect2.top + rect2.height/2;
    menu.querySelectorAll('.radial-btn').forEach(function(b, i2) {
      var a = (i2 / items.length) * Math.PI * 2 - Math.PI/2;
      b.style.left = (cx2 + Math.cos(a) * r - 28) + 'px';
      b.style.top = (cy2 + Math.sin(a) * r - 28) + 'px';
    });
  };
  document.addEventListener('scroll', updateRadialPos, {passive:true});
  window.addEventListener('resize', updateRadialPos);
}
var updateRadialPos = function(){};

function removeSidebar() { document.getElementById('sidebar-nav').style.display = 'none'; }
function applySidebar() { document.getElementById('sidebar-nav').style.display = 'flex'; }
window.sidebarNav = function(page) { showPage(page); document.querySelectorAll('#sidebar-nav .sidebar-btn').forEach(function(b){ b.classList.toggle('active', b.getAttribute('data-page')===page); }); };

function removeDashboard() { document.getElementById('dashboard-overlay').style.display = 'none'; document.getElementById('page-home').style.display = ''; }
function applyDashboard() { document.getElementById('dashboard-overlay').style.display = 'flex'; document.getElementById('page-home').style.display = 'none'; updateDashboardValues(); }
function updateDashboardValues() {
  setText('dash-status-val', app.connected ? 'Conectado' : 'Desconectado');
  var badge = document.getElementById('dash-status-badge');
  if (badge) { badge.textContent = app.connected ? 'ON' : 'OFF'; badge.style.background = app.connected ? 'rgba(16,185,129,0.15)' : 'rgba(239,68,68,0.15)'; badge.style.color = app.connected ? '#10b981' : '#ef4444'; }
  setText('dash-server-val', (document.getElementById('server-title')||{}).textContent||'Auto');
  setText('dash-dl-val', (document.getElementById('speed-dl')||{}).textContent||'0 B/s');
  setText('dash-ul-val', (document.getElementById('speed-ul')||{}).textContent||'0 B/s');
  setText('config-version', A.getVersion()||'v1.0');
}
setInterval(function(){ if(currentRadical==='dashboard') updateDashboardValues(); }, 2000);
window.dashboardAction = function(action) {
  if (action === 'connect') { document.getElementById('btn-connect').click(); }
  else if (action === 'servers') { if (app.connected) { toast('Desconecte antes de trocar de rede.', 'err'); return; } buildServerList('normal'); openModal('modal-servers'); }
  else if (action === 'creds') { if (app.connected) { toast('Desconecte para alterar credenciais.', 'err'); return; } toggleCredsMode(); }
