function terminalExec(cmd) {
  var out = document.getElementById('terminal-output'); if (!out) return;
  cmd = cmd.trim().toLowerCase(); var response = '';
  if (cmd === 'help') { response = 'Commands:\n  connect    - Start VPN\n  disconnect - Stop VPN\n  status     - Show status\n  servers    - List servers\n  logs       - View logs\n  clear      - Clear screen\n  exit       - Exit terminal\n  help       - This help'; }
  else if (cmd === 'connect') { A.connect(); applyState('INICIANDO'); response = 'Connecting...'; }
  else if (cmd === 'disconnect') { if (app.connected) { A.connect(); applyState('PARANDO'); response = 'Disconnecting...'; } else response = 'Not connected.'; }
  else if (cmd === 'status') { response = 'Status: ' + app.rawState + '\nConnected: ' + (app.connected ? 'Yes' : 'No'); }
  else if (cmd === 'servers') { var servers = A.getServers(); response = servers.length ? servers.map(function(s,i){ return '  ['+i+'] '+s.Name; }).join('\n') : 'No servers loaded.'; }
  else if (cmd === 'logs') { var logs = A.getLogs(); response = logs.length ? logs.slice(-5).map(function(l){ return '  ['+l.level+'] '+l.message; }).join('\n') : 'No logs.'; }
  else if (cmd === 'clear') { out.innerHTML = ''; return; }
  else if (cmd === 'exit') { setRadical('none'); return; }
  else if (cmd) { response = 'Unknown command: ' + cmd + '\nType "help" for commands.'; }
  if (response) out.innerHTML += '\n<span style="color:#0f0;">root@yoru:~$</span> ' + cmd + '\n' + response + '\n';
