function updateBlockedState() {
  var connected = app.connected;
  var credsCard = $('creds-card');
  var serverCard = $('select-server');
  var premiumCard = $('select-premium');
  var settingsCard = $('settings-card');

  var cards = [credsCard, serverCard, premiumCard, settingsCard];
  cards.forEach(function(card) {
    if (!card) return;
    if (connected) {
      card.classList.add('blocked');
    } else {
      card.classList.remove('blocked');
    }
  });

  var inputs = document.querySelectorAll('.blocked input, .blocked select, .blocked .creds-toggle');
  if (connected) {
    inputs.forEach(function(el) { el.disabled = true; });
  } else {
    inputs.forEach(function(el) { el.disabled = false; });
  }

  // Botão conectar/desconectar NUNCA deve ser bloqueado pelo estado de edição
  var btnConnect = $('btn-connect');
  var btnLogs = $('btn-logs-quick');
  if (btnConnect) btnConnect.disabled = app.busy; // só desabilita durante transições
  if (btnLogs) btnLogs.disabled = false;
}

function applyState(raw, detail) {
  raw=String(raw||'NOPROCESS').toUpperCase().trim();
  app.rawState=raw;
  var s=STATE[raw]||STATE['NOPROCESS'];
  ALL_STATE_CLASSES.forEach(function(c){ document.body.classList.remove(c); });
  if(s.cls) document.body.classList.add(s.cls);
  setText('status-label',s.label);
  setText('status-detail',detail||s.sub);
  setText('btn-connect-text',s.btn||'Conectar');
  app.connected=(raw==='CONECTADO');
  app.busy=['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO','PARANDO'].indexOf(raw)>=0;
  var btn = $('btn-connect'); if (btn) btn.disabled = app.busy;
  if(app.connected && !app.startedAt){ app.startedAt=Date.now(); startTimer(); }
  if(!app.connected && !app.busy){ if(app.startedAt){ app.startedAt=0; stopTimer(); setText('timer-val','00:00'); } var tb=$('timer-bar'); if(tb) tb.classList.remove('show'); }
