window.onLogAdded=function(itemJson){ var container=$('log-container'); if(!container) return; try{ var item=typeof itemJson==='string'?JSON.parse(itemJson):itemJson; var level=String(item.level||'INFO').toUpperCase(); var div=document.createElement('div'); div.className='log-entry '+level; div.innerHTML='<span class="log-time">['+esc(formatLogTime(item.time||Date.now()))+']</span> <span>'+esc(item.message||'')+'</span>'; container.insertBefore(div,container.firstChild); } catch(e){} };
window.onLogsCleared = function(){ var c=$('log-container'); if(c) c.innerHTML=''; };
window.onServerChanged = function(){ refreshSelected(); var pg=$('page-servers'); if(pg&&pg.classList.contains('active')) buildServerListPage(); };
window.onConfigUpdated = function(){ refreshInfo(); refreshSelected(); toast('Dados sincronizados!','ok'); };
window.onAdLoading = function(){ var btn=$('btn-watch-ad'); if(btn){ btn.textContent='Carregando...'; btn.disabled=true; } };
window.onTimeAdded = function(newTotalMs){ if(timeHandle) clearInterval(timeHandle); updateTimeDisplay(newTotalMs); startTimeCountdown(newTotalMs); baseTimeMs=Math.max(baseTimeMs,7200000); var btn=$('btn-watch-ad'); if(btn){ btn.textContent='Assistir Anúncio (+2 Horas)'; btn.disabled=false; } toast('+2 Horas concedidas!','ok'); };
window.onAdFailed=function(){ var btn=$('btn-watch-ad'); if(btn){ btn.textContent='Assistir Anúncio (+2 Horas)'; btn.disabled=false; } toast('Anúncio falhou.','err'); };

function loadSettings() {
  var s = A.getSettings();
  function setChk(id, val) { var el = $(id); if (el) el.checked = !!val; }
  function setVal(id, val) { var el = $(id); if (el && val !== undefined && val !== null) el.value = val; }
  function setSel(id, val) { var el = $(id); if (el && val) el.value = val; }
  setChk('cfg-dns-forward', s.dnsForward !== undefined ? s.dnsForward : true);
  setVal('cfg-dns1', s.dnsResolver || '1.1.1.1'); setVal('cfg-dns2', s.dnsResolver2 || '1.0.0.1');
  setSel('cfg-ip-version', s.ipVersion || 'auto'); setSel('cfg-tls-version', s.tlsVersion || 'auto');
  setChk('cfg-udp-forward', s.udpForward !== undefined ? s.udpForward : false); setVal('cfg-udp-resolver', s.udpResolver || '127.0.0.1:7300');
  setVal('cfg-pinger', s.pinger !== undefined ? s.pinger : 3); setChk('cfg-adaptive', s.adaptiveConnector !== undefined ? s.adaptiveConnector : true);
  setChk('cfg-ssh-compression', s.sshCompression || false); setChk('cfg-no-delay', s.disableDelay || false);
  setChk('cfg-xray-enabled', s.xrayEnabled || false); setSel('cfg-xray-protocol', s.xrayProtocol || 'vmess');
  setChk('cfg-wakelock', s.cpuWakeLock || false); setChk('cfg-debug', s.modeDebug || false);
  setChk('cfg-auto-clear', s.autoClearLogs !== undefined ? s.autoClearLogs : true); setChk('cfg-vibrate', s.vibrate !== undefined ? s.vibrate : true);
  updateDepRows();
}
function updateDepRows() {
  var dnsOn = ($('cfg-dns-forward') || {}).checked; document.querySelectorAll('.dep-dns').forEach(function(r) { r.style.opacity = dnsOn ? '1' : '0.35'; var inp = r.querySelector('input'); if (inp) inp.disabled = !dnsOn; });
  var udpOn = ($('cfg-udp-forward') || {}).checked; document.querySelectorAll('.dep-udp').forEach(function(r) { r.style.opacity = udpOn ? '1' : '0.35'; var inp = r.querySelector('input'); if (inp) inp.disabled = !udpOn; });
  var xrayOn = ($('cfg-xray-enabled') || {}).checked; document.querySelectorAll('.dep-xray').forEach(function(r) { r.style.opacity = xrayOn ? '1' : '0.35'; var sel = r.querySelector('select'); if (sel) sel.disabled = !xrayOn; });
}
function saveSettings() {
  if (app.connected) { toast('Desconecte para alterar configurações.', 'err'); return; }
  function chk(id) { var el = $(id); return el ? el.checked : false; }
  function val(id) { var el = $(id); return el ? el.value.trim() : ''; }
  var obj = { dnsForward: chk('cfg-dns-forward'), dnsResolver: val('cfg-dns1')||'1.1.1.1', dnsResolver2: val('cfg-dns2')||'1.0.0.1', ipVersion: val('cfg-ip-version')||'auto', tlsVersion: val('cfg-tls-version')||'auto', udpForward: chk('cfg-udp-forward'), udpResolver: val('cfg-udp-resolver')||'127.0.0.1:7300', pinger: parseInt(val('cfg-pinger'))||3, adaptiveConnector: chk('cfg-adaptive'), sshCompression: chk('cfg-ssh-compression'), disableDelay: chk('cfg-no-delay'), xrayEnabled: chk('cfg-xray-enabled'), xrayProtocol: val('cfg-xray-protocol')||'vmess', cpuWakeLock: chk('cfg-wakelock'), modeDebug: chk('cfg-debug'), autoClearLogs: chk('cfg-auto-clear'), vibrate: chk('cfg-vibrate') };
  A.saveSettings(obj); toast('Configurações salvas!', 'ok');
}

function updateCelestial() {
  var hour = new Date().getHours(), isDay = hour >= 6 && hour < 18;
  var celestial = document.querySelector('.celestial-body');
  if (celestial) { celestial.className = 'celestial-body ' + (isDay ? 'celestial-sun' : 'celestial-moon'); celestial.innerText = isDay ? '☀️' : '🌙'; }
}

function bind(){
  var btnConn=$('btn-connect');
  if(btnConn) btnConn.onclick=function(){
    var raw=app.rawState; if(raw==='PARANDO') return;
    autoSaveCredentials();
    A.connect();
    if(raw==='CONECTADO') applyState('PARANDO','Encerrando túnel...');
    else if(['INICIANDO','CONECTANDO','AUTENTICANDO','AGUARDANDO','RECONECTANDO'].indexOf(raw)<0) applyState('INICIANDO','Preparando conexão...');
  };
  var btnLogsQuick = $('btn-logs-quick');
  if(btnLogsQuick) btnLogsQuick.onclick = function(){ renderLogs(); openModal('modal-logs'); };

  var sServ=$('select-server'); if(sServ) sServ.onclick=function(){ if(app.connected){ toast('Desconecte antes de trocar de rede.','err'); return; } buildServerList('normal'); openModal('modal-servers'); };
  var pCard=$('select-premium'); if(pCard) pCard.onclick=function(){ if(app.connected){ toast('Desconecte antes de trocar de rede.','err'); return; } buildServerList('premium'); openModal('modal-servers'); };
  var credsToggle = $('creds-type-toggle'); if (credsToggle) credsToggle.onclick = toggleCredsMode;
  var tUpd=$('tool-update'); if(tUpd) tUpd.onclick=function(){ toast('Sincronizando...',''); A.checkUpdate(); };
  var tLog=$('tool-logs'); if(tLog) tLog.onclick=function(){ renderLogs(); openModal('modal-logs'); };
  var rLog=$('btn-refresh-logs'); if(rLog) rLog.onclick=function(){ renderLogs(); };
  var cLog=$('btn-clear-logs'); if(cLog) cLog.onclick=function(){ A.clearLogs(); var c=$('log-container'); if(c) c.innerHTML='<div style="color:var(--text-muted);padding:8px">Limpo.</div>'; };
  var btnLayouts=$('btn-open-layouts'); if(btnLayouts) btnLayouts.onclick=function(){ openModal('modal-layouts'); };
  var dnsToggle=$('cfg-dns-forward'); if(dnsToggle) dnsToggle.onchange=updateDepRows;
  var udpToggle=$('cfg-udp-forward'); if(udpToggle) udpToggle.onchange=updateDepRows;
  var xrayToggle=$('cfg-xray-enabled'); if(xrayToggle) xrayToggle.onchange=updateDepRows;
  var btnSaveSettings=$('btn-settings-save'); if(btnSaveSettings) btnSaveSettings.onclick=saveSettings;
  document.querySelectorAll('.modal-close').forEach(function(b){ b.onclick=closeModal; });
  var mMask=$('modal-mask'); if(mMask) mMask.onclick=function(e){ if(e.target===mMask) closeModal(); };
  var btnAd=$('btn-watch-ad'); if(btnAd) btnAd.onclick=function(){ btnAd.textContent='Aguarde...'; btnAd.disabled=true; A.watchAd(); };
  var termInput = document.getElementById('terminal-input'); if (termInput) termInput.addEventListener('keydown', function(e) { if (e.key === 'Enter') { var cmd = termInput.value; terminalExec(cmd); termInput.value = ''; } });
  document.querySelectorAll('#carousel-dots .carousel-dot').forEach(function(dot) { dot.onclick = function() { goCarousel(parseInt(dot.getAttribute('data-index'))); }; });
  var touchStartX = 0; var track = document.getElementById('carousel-track');
  if (track) { track.addEventListener('touchstart', function(e) { touchStartX = e.touches[0].clientX; }, {passive:true}); track.addEventListener('touchend', function(e) { var diff = touchStartX - e.changedTouches[0].clientX; if (Math.abs(diff) > 50) { if (diff > 0 && carouselIndex < 2) goCarousel(carouselIndex + 1); else if (diff < 0 && carouselIndex > 0) goCarousel(carouselIndex - 1); } }); }
  setInterval(updateCelestial, 60000);
}

function createBubbles() { for (var i = 0; i < 6; i++) { var bubble = document.createElement('div'); bubble.className = 'floating-bubble'; var size = Math.random() * 80 + 40; bubble.style.width = size + 'px'; bubble.style.height = size + 'px'; bubble.style.left = Math.random() * 100 + 'vw'; bubble.style.top = Math.random() * 100 + 'vh'; bubble.style.animationDuration = (Math.random() * 10 + 8) + 's'; bubble.style.animationDelay = Math.random() * 5 + 's'; document.body.appendChild(bubble); } for (var j = 0; j < 25; j++) { var star = document.createElement('div'); var sSize = Math.random() * 3 + 1; star.className = 'fx-star'; star.style.width = sSize + 'px'; star.style.height = sSize + 'px'; star.style.left = Math.random() * 100 + 'vw'; star.style.top = Math.random() * 100 + 'vh'; star.style.animationDuration = (Math.random() * 3 + 2) + 's'; star.style.animationDelay = Math.random() * 2 + 's'; document.body.appendChild(star); } }

function boot(){ createBubbles(); updateCelestial(); loadTheme(); loadLayout(); loadSavedCredentials(); bind(); loadRadical(); initTimeCard(); refreshInfo(); refreshSelected(); applyState(A.getStatus()); startPolling(); setInterval(refreshInfo,15000); loadSettings(); }
if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',boot); else boot();
})();
</script>

</body>
